class Solution:
    def getKth(self, lo: int, hi: int, k: int) -> int:
        def power(x):
            res = 0
            while x != 1:
                res += 1
                if x % 2 == 0:
                    x //= 2
                else:
                    x = 3 * x + 1
            return res

        res = []
        for i in range(lo, hi + 1):
            res.append((power(i), i))
        res.sort()
        return res[k - 1][1]

